// Fecha de inicio de experiencia profesional
const EXPERIENCE_START_DATE = new Date(2019, 2, 1); // Marzo 2019 (mes es 0-indexed)

// Función para calcular años de experiencia
const calculateYearsOfExperience = (): number => {
  const now = new Date();
  const diffTime = Math.abs(now.getTime() - EXPERIENCE_START_DATE.getTime());
  const diffYears = diffTime / (1000 * 60 * 60 * 24 * 365.25);
  return Math.floor(diffYears);
};

// Función para formatear años de experiencia
const getExperienceText = (years: number): string => {
  return years === 1 ? `${years} año` : `${years} años`;
};

const getExperienceTextEn = (years: number): string => {
  return years === 1 ? `${years} year` : `${years} years`;
};

const yearsOfExperience = calculateYearsOfExperience();
const workedMonths = getExperienceText(yearsOfExperience);
const workedMonthsEn = getExperienceTextEn(yearsOfExperience);

